import json
import time
import random
import os
from datetime import datetime

import modal
from fastapi import FastAPI

app = modal.App("etl-pipeline")

nfs = modal.NetworkFileSystem.from_name("etl-nfs", create_if_missing=True)
metadata_dict = modal.Dict.from_name("etl-pipeline-metadata", create_if_missing=True)

web_app = FastAPI()

def update_metadata_success(timestamp):
    run_count = metadata_dict.get("run_count", 0)
    metadata_dict["run_count"] = run_count + 1
    metadata_dict["last_run_timestamp"] = timestamp

def update_metadata_error():
    error_count = metadata_dict.get("error_count", 0)
    metadata_dict["error_count"] = error_count + 1

@app.function(network_file_systems={"/data": nfs}, retries=3, timeout=120)
def process_data(timestamp_str: str):
    try:
        raw_path = f"/data/raw_{timestamp_str}.json"
        with open(raw_path, "r") as f:
            records = json.load(f)

        # Aggregate
        stats = {}
        for r in records:
            cat = r["category"]
            val = r["value"]
            if cat not in stats:
                stats[cat] = {"count": 0, "sum": 0.0}
            stats[cat]["count"] += 1
            stats[cat]["sum"] += val

        processed_path = f"/data/processed_{timestamp_str}.json"
        with open(processed_path, "w") as f:
            json.dump(stats, f)

        # Update metadata
        update_metadata_success(timestamp_str)

    except Exception as e:
        update_metadata_error()
        raise e

@app.function(schedule=modal.Period(minutes=5), network_file_systems={"/data": nfs})
def ingest_data():
    timestamp_str = str(int(time.time()))
    categories = ["A", "B", "C", "D"]
    records = []
    for _ in range(100):
        records.append({
            "category": random.choice(categories),
            "value": random.uniform(10.0, 100.0),
            "timestamp": timestamp_str
        })

    raw_path = f"/data/raw_{timestamp_str}.json"
    with open(raw_path, "w") as f:
        json.dump(records, f)

    # Kick off processing
    process_data.remote(timestamp_str)


@web_app.get("/status")
def status():
    try:
        if not os.path.exists("/data"):
            return {"status": "Pipeline has not run yet."}

        files = os.listdir("/data")
        processed_files = [f for f in files if f.startswith("processed_") and f.endswith(".json")]
        if not processed_files:
            return {"status": "Pipeline has not run yet."}

        processed_files.sort(reverse=True)
        latest_file = processed_files[0]

        with open(f"/data/{latest_file}", "r") as f:
            stats = json.load(f)

        return {
            "status": "success",
            "latest_file": latest_file,
            "stats": stats,
            "run_count": metadata_dict.get("run_count", 0),
            "last_run_timestamp": metadata_dict.get("last_run_timestamp", None),
            "error_count": metadata_dict.get("error_count", 0)
        }
    except Exception as e:
        return {"status": "error", "message": str(e)}

@app.function(network_file_systems={"/data": nfs})
@modal.asgi_app()
def web_endpoint():
    return web_app

@app.local_entrypoint()
def run_manual():
    print("Running manual ingest...")
    ingest_data.remote()
    print("Manual ingest triggered.")

